     1→import { NextRequest, NextResponse } from "next/server";
     2→import { db } from "@/lib/db";
     3→import { recommendations, brands } from "@/lib/db/schema";
     4→import { eq, and } from "drizzle-orm";
     5→import { z } from "zod";
     6→import { getOrganizationId } from "@/lib/auth";
     7→
     8→// Validation schema for status update
     9→const updateStatusSchema = z.object({
    10→  status: z.enum(["pending", "in_progress", "completed", "dismissed"]),
    11→  notes: z.string().optional().nullable(),
    12→});
    13→
    14→type RouteContext = {
    15→  params: Promise<{ id: string }>;
    16→};
    17→
    18→/**
    19→ * PATCH /api/recommendations/[id]/status
    20→ * Updates the status of a recommendation
    21→ */
    22→export async function PATCH(request: NextRequest, context: RouteContext) {
    23→  try {
    24→    const { id } = await context.params;
    25→    const orgId = await getOrganizationId();
    26→
    27→    if (!orgId) {
    28→      return NextResponse.json(
    29→        { success: false, error: "Organization not found" },
    30→        { status: 401 }
    31→      );
    32→    }
    33→
    34→    // Get existing recommendation
    35→    const existingRec = await db
    36→      .select()
    37→      .from(recommendations)
    38→      .where(eq(recommendations.id, id))
    39→      .limit(1);
    40→
    41→    if (existingRec.length === 0) {
    42→      return NextResponse.json(
    43→        { success: false, error: "Recommendation not found" },
    44→        { status: 404 }
    45→      );
    46→    }
    47→
    48→    // Verify brand belongs to organization
    49→    const brand = await db
    50→      .select()
    51→      .from(brands)
    52→      .where(
    53→        and(
    54→          eq(brands.id, existingRec[0].brandId),
    55→          eq(brands.organizationId, orgId),
    56→          eq(brands.isActive, true)
    57→        )
    58→      )
    59→      .limit(1);
    60→
    61→    if (brand.length === 0) {
    62→      return NextResponse.json(
    63→        { success: false, error: "Recommendation not found" },
    64→        { status: 404 }
    65→      );
    66→    }
    67→
    68→    const body = await request.json();
    69→    const validatedData = updateStatusSchema.parse(body);
    70→
    71→    // Prepare update data
    72→    const updateData: Record<string, unknown> = {
    73→      status: validatedData.status,
    74→      updatedAt: new Date(),
    75→    };
    76→
    77→    // Set timestamps based on status change
    78→    if (validatedData.status === "completed" && existingRec[0].status !== "completed") {
    79→      updateData.completedAt = new Date();
    80→    }
    81→
    82→    if (validatedData.status === "dismissed" && existingRec[0].status !== "dismissed") {
    83→      updateData.dismissedAt = new Date();
    84→    }
    85→
    86→    // Clear completion/dismissal timestamps if status is being reverted
    87→    if (
    88→      validatedData.status !== "completed" &&
    89→      validatedData.status !== "dismissed"
    90→    ) {
    91→      if (existingRec[0].status === "completed") {
    92→        updateData.completedAt = null;
    93→      }
    94→      if (existingRec[0].status === "dismissed") {
    95→        updateData.dismissedAt = null;
    96→      }
    97→    }
    98→
    99→    // Add notes if provided
   100→    if (validatedData.notes !== undefined) {
   101→      updateData.notes = validatedData.notes;
   102→    }
   103→
   104→    const updatedRec = await db
   105→      .update(recommendations)
   106→      .set(updateData)
   107→      .where(eq(recommendations.id, id))
   108→      .returning();
   109→
   110→    return NextResponse.json({
   111→      success: true,
   112→      data: updatedRec[0],
   113→      meta: {
   114→        previousStatus: existingRec[0].status,
   115→        newStatus: validatedData.status,
   116→        timestamp: new Date().toISOString(),
   117→      },
   118→    });
   119→  } catch (error) {
   120→    if (error instanceof z.ZodError) {
   121→      return NextResponse.json(
   122→        {
   123→          success: false,
   124→          error: "Validation error",
   125→          details: error.issues,
   126→        },
   127→        { status: 400 }
   128→      );
   129→    }
   130→
   131→    const message = error instanceof Error ? error.message : "Unknown error";
   132→    return NextResponse.json(
   133→      { success: false, error: message },
   134→      { status: 500 }
   135→    );
   136→  }
   137→}
