     1→/**
     2→ * Priority Scoring Module (F107)
     3→ * Score recommendations by impact (40%), effort (30%), urgency (20%), confidence (10%)
     4→ */
     5→
     6→import {
     7→  Recommendation,
     8→  PriorityWeights,
     9→  PriorityLevel,
    10→  RecommendationImpact,
    11→  RecommendationEffort,
    12→} from "./types";
    13→
    14→// Default weights as specified in F107
    15→export const DEFAULT_WEIGHTS: PriorityWeights = {
    16→  impact: 0.40,    // 40%
    17→  effort: 0.30,    // 30%
    18→  urgency: 0.20,   // 20%
    19→  confidence: 0.10, // 10%
    20→};
    21→
    22→/**
    23→ * Calculate priority score for a recommendation
    24→ * Higher score = higher priority
    25→ */
    26→export function calculatePriorityScore(
    27→  impact: number,
    28→  effort: number,
    29→  urgency: number,
    30→  confidence: number,
    31→  weights: PriorityWeights = DEFAULT_WEIGHTS
    32→): number {
    33→  // Normalize all scores to 0-100
    34→  const normalizedImpact = Math.min(100, Math.max(0, impact));
    35→  const normalizedEffort = Math.min(100, Math.max(0, 100 - effort)); // Invert: lower effort = higher score
    36→  const normalizedUrgency = Math.min(100, Math.max(0, urgency));
    37→  const normalizedConfidence = Math.min(100, Math.max(0, confidence));
    38→
    39→  // Calculate weighted score
